  'foshan/lion': ('Barongsai', 'Dikenal sebagai ibu kota barongsai selatan, pertunjukan singa yang penuh warna ini sering melompat di atas tiang-tiang tinggi saat festival.'),
  'foshan/ceramic': ('Keramik Shiwan', 'Tungku pembakaran berusia ribuan tahun masih terus memproduksi figurin keramik Shiwan yang ekspresif.'),
  'foshan/opera': ('Opera Kanton', 'Seni panggung yang paling dicintai di Tiongkok selatan ini berkembang pesat di wilayah ini.'),
  'guiyang/pavilion': ('Paviliun Jiaxiu', 'Paviliun tiga tingkat di atas Sungai Nanming ini telah menjadi ikon kota selama 400 tahun.'),
  'guiyang/sourfish': ('Sup Ikan Asam', 'Ikan yang dimasak dalam kaldu tomat fermentasi yang segar merupakan hidangan khas dari Guizhou.'),
  'guiyang/waterfall': ('Air Terjun Huangguoshu', 'Salah satu air terjun terbesar di Asia ini mengalir deras dan sering kali memunculkan pelangi di sekitarnya.'),
  'guiyang/miao': ('Budaya Miao', 'Festival dan kerajinan sulaman masyarakat Miao yang mengenakan mahkota perak menghidupkan suasana desa-desa di pegunungan.'),
  'changchun/film': ('Kota Film', 'Studio tempat lahirnya sinema Tiongkok berdiri di sini, menjadikannya sebagai \'Hollywood dari Timur\'.'),
  'changchun/car': ('Kota Otomotif', 'Mobil buatan dalam negeri pertama Tiongkok diproduksi di pabrik-pabrik kota ini, menjadikannya ibu kota otomotif nasional.'),
  'changchun/palace': ('Istana Boneka', 'Istana tempat kaisar terakhir Tiongkok pernah tinggal ini menjadi saksi bisu sejarah yang penuh gejolak.'),
  'changchun/snow': ('Salju Musim Dingin', 'Selama musim dingin yang panjang, kota ini berkilau dengan pahatan es dan arena ski yang memukau.'),
  'xining/lake': ('Danau Qinghai', 'Danau air asin terbesar di Tiongkok ini terkenal dengan hamparan bunga kanola kuning yang mengelilinginya saat musim panas.'),
  'xining/monastery': ('Biara Kumbum', 'Salah satu dari enam biara besar Buddhisme Tibet ini tersohor karena karya seni pahat dari mentega yak.'),
  'xining/flower': ('Bunga Kanola', 'Pada bulan Juli, dataran tinggi ini diselimuti oleh hamparan bunga kanola keemasan hingga ke cakrawala.'),
  'xining/lamb': ('Daging Yak dan Domba', 'Mi tarik dan sate domba khas kuliner Hui dan Tibet menjadi cita rasa utama di dataran tinggi ini.'),
  'guilin/karst': ('Karst Sungai Li', 'Puncak-puncak batu kapur yang menyembul dari kabut merupakan pemandangan yang tertera pada uang kertas 20 yuan.'),
  'guilin/elephant': ('Bukit Belalai Gajah', 'Batu berbentuk gajah yang sedang mencelupkan belalainya ke sungai ini merupakan lambang kebanggaan kota Guilin.'),
  'guilin/terrace': ('Terasering Sawah Longji', 'Terasering \'Punggung Naga\' yang melingkari lereng bukit ini adalah tangga raksasa hasil kerja keras selama berabad-abad.'),
  'guilin/osmanthus': ('Bunga Osmanthus', 'Nama kota ini berarti \'hutan osmanthus\', dan saat musim gugur, kota ini dipenuhi aroma manis bunga tersebut.'),
  'wenzhou/merchant': ('Semangat Pedagang', 'Sering dijuluki sebagai \'Yahudi Tiongkok\', para pengusaha Wenzhou membangun jaringan bisnis di seluruh dunia.'),
  'wenzhou/shoe': ('Sepatu dan Kulit', 'Sebagian besar pasokan sepatu kulit dunia diproduksi di kota industri ini.'),
  'wenzhou/mountain': ('Pegunungan Yandang', 'Terkenal dengan air terjun dan puncak-puncak tajamnya, pegunungan ini dijuluki sebagai \'gunung pertama di tepi laut\'.'),
  'wenzhou/seafood': ('Hidangan Laut', 'Cumi-cumi, kerang, dan ikan dari Laut Tiongkok Timur menjadi bahan utama dalam santapan masyarakat setempat.'),
  'tangshan/memorial': ('Monumen Gempa Bumi', 'Taman peringatan untuk gempa besar tahun 1976 ini menjadi simbol kebangkitan kota Tangshan.'),
  'tangshan/coal': ('Tambang Batu Bara dan Baja', 'Tambang batu bara dan jalur kereta api modern pertama di Tiongkok dibuka di sini sebagai pusat industri awal.'),
  'tangshan/ceramic': ('Keramik Tangshan', 'Dikenal sebagai kota porselen di utara, keramik tulang dari kota ini menghiasi meja makan dengan keanggunan.'),
  'tangshan/lake': ('Taman Nanhu', 'Taman danau yang dibangun di atas bekas lubang tambang ini kini berfungsi sebagai paru-paru hijau kota.'),
  'anshan/steel': ('Kota Baja', 'Pabrik baja terbesar di Tiongkok didirikan di sini, menjadikan kota ini sebagai ibu kota baja nasional.'),
  'anshan/jade': ('Giok Xiuyan', 'Kota ini merupakan pusat giok Tiongkok dan menjadi tempat bagi ukiran giok terbesar di dunia.'),
  'anshan/mountain': ('Gunung Qian', 'Gunung yang dikenal sebagai Puncak Seribu Teratai ini merupakan puncak suci di wilayah utara dengan kuil-kuil dan tebing yang indah.'),
  'anshan/spring': ('Pemandian Air Panas Tanggangzi', 'Pemandian air panas ini telah dicari selama ribuan tahun untuk penyembuhan dan pernah dikunjungi oleh para kaisar.'),
  'linyi/market': ('Pasar Grosir', 'Pusat grosir terbesar di Tiongkok Utara ini mendistribusikan berbagai barang ke seluruh penjuru negeri.'),
  'linyi/brush': ('Master Kaligrafi', 'Kota ini adalah tempat kelahiran Wang Xizhi, sang maestro kaligrafi Tiongkok, dan dikenal sebagai tanah tinta.'),
  'linyi/mountain': ('Gunung Meng', 'Gunung tertinggi kedua di Shandong ini merupakan kawasan dengan udara bersih dan air terjun yang menyegarkan.'),
  'linyi/pancake': ('Pancake Yimeng', 'Pancake jagung tipis yang disebut jianbing ini merupakan makanan pokok tradisional masyarakat pegunungan Yimeng.'),
  'cangzhou/lion': ('Singa Besi', 'Patung singa besi raksasa berusia 1.100 tahun ini menjadi simbol kebanggaan kota.'),
  'cangzhou/martial': ('Seni Bela Diri', 'Dikenal sebagai rumah wushu di Tiongkok, kota ini melahirkan banyak ahli bela diri dan perguruan ternama.'),
  'cangzhou/canal': ('Kanal Besar', 'Kanal Besar Beijing-Hangzhou melintasi kota ini, di mana dermaga-dermaga kuno masih berdiri hingga kini.'),
  'cangzhou/jujube': ('Kurma Jujube Emas', 'Kurma jujube \'benang emas\' yang manis dan berkulit tipis ini dijuluki sebagai raja buah kering.'),
  'nantong/textile': ('Kota Tekstil', 'Sebagai pusat tekstil rumah tangga di Tiongkok, produk kain katun dari kota ini telah dipasarkan ke seluruh dunia.'),
  'nantong/mountain': ('Gunung Lang', 'Terletak di muara Sungai Yangtze, bukit suci dengan lima puncak ini menjadi destinasi ziarah sekaligus tempat untuk menikmati pemandangan.'),
  'nantong/kite': ('Layang-layang Bersiul', 'Layang-layang banyao yang dilengkapi peluit sehingga mengeluarkan suara dengungan merupakan kerajinan tradisional khas kota ini.'),
  'nantong/school': ('Pelopor Pendidikan', 'Industrialis Zhang Jian mendirikan sekolah modern dan museum pertama di Tiongkok di kota ini.'),
  'taizhou/opera': ('Mei Lanfang', 'Kota ini merupakan kampung halaman dari Mei Lanfang, maestro legendaris opera Peking.'),
  'taizhou/tea': ('Teh Pagi', 'Ritual sarapan zaocha yang terdiri dari bakpao kukus dan teh seduh telah menjadi tradisi masyarakat setempat.'),
  'taizhou/boat': ('Festival Perahu Qintong', 'Festival yang melibatkan ratusan pendayung perahu ini selalu memeriahkan suasana sungai setiap musim semi.'),
  'taizhou/meatball': ('Bakso Kepala Singa', 'Bakso babi berukuran besar dengan tekstur lembut ini merupakan hidangan klasik dari kuliner Huaiyang.'),
  'jinhua/ham': ('Ham Jinhua', 'Daging ham berwarna merah yang diawetkan dengan metode berusia berabad-abad ini adalah yang paling terkenal di Tiongkok.'),
  'jinhua/film': ('Studio Hengdian', 'Sebagai lokasi syuting luar ruangan terbesar di dunia, tempat ini menjadi latar bagi banyak drama kolosal Tiongkok.'),
  'jinhua/cave': ('Gua Shuanglong', 'Gua bawah tanah yang dimasuki dengan perahu melalui celah batu rendah ini menawarkan pemandangan yang memukau.'),
  'jinhua/bridge': ('Jembatan Kuno', 'Jembatan batu melengkung dan kota air di sini mencerminkan keanggunan khas wilayah Jiangnan.'),
  'wuhu/park': ('Fangte Wonderland', 'Salah satu taman hiburan terbesar di Tiongkok ini menawarkan berbagai wahana seru bagi keluarga.'),
  'wuhu/ironart': ('Seni Lukis Besi', 'Seni lukis besi yang elegan dan ditempa dari besi tempa merupakan kerajinan tangan yang telah berusia 300 tahun.'),
  'wuhu/rice': ('Pelabuhan Beras', 'Kota yang terletak di tepi Sungai Yangtze ini secara historis merupakan pasar beras terbesar di Tiongkok.'),
  'wuhu/river': ('Pelabuhan Yangtze', 'Pelabuhan sungai yang sibuk ini menjadikan kota tersebut sebagai gerbang laut bagi Provinsi Anhui.'),
  'huangshan/peak': ('Gunung Huangshan', 'Dengan puncak granit, lautan awan, dan pohon pinus yang unik, gunung ini merupakan gunung paling terkenal di Tiongkok.'),
  'huangshan/village': ('Desa Hongcun', 'Desa bergaya Hui yang dikelilingi air dengan dinding putih ini terdaftar sebagai Situs Warisan Dunia UNESCO dan tampak seperti lukisan hidup.'),
  'huangshan/tea': ('Teh Maofeng', 'Teh hijau berujung halus yang dipetik di lereng berkabut ini merupakan salah satu dari sepuluh teh paling terkenal di Tiongkok.'),
  'huangshan/ink': ('Tinta dan Seni Huizhou', 'Tinta Hui, rumah kayu berukir, dan kaligrafi merupakan harta karun budaya di wilayah ini.'),
  'yichun/moon': ('Gunung Mingyue', 'Gunung \'Bulan Terang\' ini terkenal dengan pemandian air panas dan pemandangan dari kereta gantungnya.'),
  'yichun/spring': ('Pemandian Air Panas', 'Mata air panas kaya selenium yang langka menjadikan kota ini sebagai pusat pemandian spa di Tiongkok.'),
  'yichun/zen': ('Buddhisme Chan', 'Kuil-kuil di pegunungan yang berakar pada sekte Chan Tiongkok mengajak pengunjung untuk merasakan ketenangan.'),
  'yichun/rice': ('Dataran Padi', 'Dataran subur Yuan-He telah lama menjadi lumbung padi bagi Provinsi Jiangxi.'),
  'zhangzhou/narcissus': ('Bunga Bakung', 'Bunga bakung paling terkenal di Tiongkok tumbuh di sini dan menjadi lambang perayaan musim semi.'),
  'zhangzhou/tulou': ('Rumah Tanah Hakka', 'Benteng raksasa berbentuk bulat dari tanah padat ini terdaftar di UNESCO dan mampu menampung satu desa di bawah satu atap.'),
  'zhangzhou/banana': ('Buah Tropis', 'Kebun pisang, lengkeng, dan jeruk keprok menjaga delta yang hangat ini tetap hijau sepanjang tahun.'),
  'zhangzhou/coast': ('Pulau Dongshan', 'Dengan pantai keemasan dan desa nelayan, pulau ini merupakan permata di pesisir selatan.'),
  'guangzhou/tower': ('Canton Tower', 'Menara ramping yang dijuluki \'Pinggang Kecil\' ini merupakan salah satu menara tertinggi di dunia yang menghiasi kota dengan warna-warni lampu malam.'),
  'guangzhou/dimsum': ('Yum Cha', 'Tradisi minum teh dan menyantap dim sum yang dikukus dalam keranjang bambu adalah jiwa dari kuliner Kanton.'),
  'guangzhou/academy': ('Akademi Klan Chen', 'Terkenal dengan ukiran kayu dan hiasan keramiknya, aula klan ini merupakan mahakarya kerajinan khas Kanton.'),
  'guangzhou/flower': ('Kota Bunga', 'Karena bunganya mekar sepanjang tahun, Guangzhou mengadakan pameran bunga besar-besaran setiap tahun baru dan dijuluki sebagai \'Kota Bunga\'.'),
  'wuhan/crane': ('Menara Bangau Kuning', 'Menghadap ke Sungai Yangtze, menara berusia ribuan tahun ini telah menginspirasi banyak puisi Tiongkok yang paling terkenal.'),
  'wuhan/noodle': ('Mi Kering Pedas', 'Mi kering dengan saus wijen merupakan menu sarapan yang wajib dicoba di Wuhan.'),
  'wuhan/duckneck': ('Leher Bebek Pedas', 'Leher bebek rebus yang pedas adalah camilan favorit warga kota untuk menemani obrolan larut malam.'),
  'wuhan/university': ('Bunga Sakura Kampus', 'Bunga sakura di Universitas Wuhan menarik ribuan pengunjung setiap musim semi.'),
  'tianjin/eye': ('Tianjin Eye', 'Kincir ria yang dibangun di atas jembatan ini menyuguhkan pemandangan kedua sisi sungai sekaligus.'),
  'tianjin/baozi': ('Bakpao Goubuli', 'Bakpao kukus isi daging babi dengan lipatan khas ini telah menjadi ikon kuliner kota selama 150 tahun.'),
  'tianjin/crosstalk': ('Komedi Crosstalk', 'Komedi verbal dua orang yang disebut \'xiangsheng\' adalah tradisi Tianjin yang lahir di kedai-kedai teh setempat.'),
  'tianjin/architecture': ('Kawasan Eropa', 'Vila-vila bergaya Eropa di Five Great Avenues membuat kota ini dijuluki sebagai museum arsitektur.'),
  'xiamen/island': ('Pulau Gulangyu', 'Jalanan bebas kendaraan dan vila-vila kolonial menjadikan pulau yang terdaftar di UNESCO ini sebagai museum terbuka.'),
  'xiamen/piano': ('Pulau Piano', 'Dengan jumlah piano per kapita terbanyak, Gulangyu dikenal sebagai \'pulau piano\'.'),
  'xiamen/egret': ('Bangau Putih', 'Bangau putih, yang menjadi lambang kota, mengingatkan kita pada nama lama kota ini yaitu \'pulau bangau\'.'),
  'xiamen/oyster': ('Omelet Tiram', 'Omelet renyah yang terbuat dari tiram segar dan telur ini merupakan hidangan andalan kuliner pesisir.'),
  'harbin/ice': ('Festival Es', 'Festival musim dingin yang menampilkan istana es raksasa berlampu ini adalah yang terbesar di dunia.'),
  'harbin/cathedral': ('Katedral Santa Sofia', 'Katedral Ortodoks Rusia dengan kubah bawang ini merupakan lambang sejarah Eropa di kota Harbin.'),
  'harbin/sausage': ('Sosis Merah', 'Sosis asap berwarna merah khas Rusia ini merupakan kuliner legendaris yang telah ada selama seabad di Harbin.'),
  'harbin/accordion': ('Kota Musik', 'Berkat warisan budaya Rusia yang kental, Harbin menjadi tempat berdirinya orkestra simfoni pertama di Tiongkok.'),
  'fuzhou/alley': ('Tiga Jalur dan Tujuh Gang', 'Kawasan bersejarah dengan dinding putih dan atap hitam ini merupakan museum hidup arsitektur era Dinasti Ming dan Qing.'),
  'fuzhou/banyan': ('Kota Beringin', 'Pohon beringin raksasa yang berusia ratusan tahun menaungi jalanan kota, menjuluki Fuzhou sebagai \'Kota Beringin\'.'),
  'fuzhou/hotspring': ('Pemandian Air Panas', 'Mata air panas alami yang muncul di pusat kota telah digunakan sebagai pemandian umum selama seribu tahun.'),
  'fuzhou/soup': ('Buddha Jumps Over the Wall', 'Sup mewah yang dimasak dari puluhan bahan pilihan ini merupakan mahakarya kuliner khas Fujian.'),
  'dongguan/robot': ('Pabrik Dunia', 'Dengan pabrik-pabrik yang terotomatisasi, Dongguan memproduksi sebagian besar kebutuhan elektronik dunia.'),
  'dongguan/basketball': ('Kota Bola Basket', 'Klub bola basket paling berprestasi di Tiongkok bermarkas di kota yang dijuluki sebagai \'Kota Bola Basket\' ini.'),
  'dongguan/keyuan': ('Taman Keyuan', 'Salah satu dari empat taman klasik paling terkenal di Guangdong yang dikagumi karena kolam dan paviliunnya yang indah.'),
  'dongguan/cannon': ('Benteng Humen', 'Benteng Humen merupakan lokasi dimulainya Perang Candu dan tempat bersejarah pembakaran candu di pesisir pantai.'),
  'lanzhou/beefnoodle': ('Mi Sapi Lanzhou', 'Dengan kaldu sapi bening dan mi tarik buatan tangan, Lanzhou dikenal sebagai ibu kota mi di Tiongkok.'),
  'lanzhou/waterwheel': ('Kincir Air', 'Kincir air raksasa di tepi Sungai Kuning melambangkan teknik irigasi yang telah digunakan selama berabad-abad.'),
  'lanzhou/statue': ('Patung Ibu Sungai Kuning', 'Patung ibu dan anak di tepi sungai ini melambangkan Sungai Kuning sebagai sumber kehidupan peradaban Tiongkok.'),
  'lanzhou/raft': ('Rakit Kulit Domba', 'Rakit tradisional yang terbuat dari kulit domba yang ditiup hingga mengembang masih digunakan untuk menyusuri Sungai Kuning.'),
  'urumqi/bazaar': ('Grand Bazaar', 'Dengan menara masjid dan kios rempah-rempah, pasar ini menghadirkan nuansa Jalur Sutra yang kental.'),
  'urumqi/tianshan': ('Danau Surgawi', 'Danau Surgawi yang terletak di bawah puncak bersalju Pegunungan Tianshan dikelilingi oleh hutan pohon cemara.'),
  'urumqi/kebab': ('Kebab Domba', 'Sate domba berbumbu yang dipanggang di atas bara api merupakan hidangan wajib bagi masyarakat Uighur.'),
  'urumqi/dance': ('Tarian Uighur', 'Tarian Uighur yang berputar dengan iringan musik drum dan rawap selalu memeriahkan setiap perayaan.'),
  'haikou/coconut': ('Kota Kelapa', 'Jalanan yang dipenuhi pohon kelapa memberikan julukan \'Kota Kelapa\' bagi Haikou.'),
  'haikou/arcade': ('Arkade Qilou', 'Bangunan bergaya qilou dengan pilar-pilar khas di wilayah selatan membentuk jalanan arkade yang teduh.'),
  'haikou/crater': ('Kawah Vulkanik', 'Kawah gunung berapi yang sudah tidak aktif kini membentuk geopark hijau di pinggiran kota.'),
  'haikou/turtle': ('Laut Tropis', 'Perairan yang hangat dan jernih dengan terumbu karang menjadikan pesisir ini habitat bagi penyu laut.'),
  'luoyang/grotto': ('Gua Longmen', 'Puluhan ribu patung Buddha yang dipahat di tebing merupakan harta karun seni warisan dunia UNESCO.'),
  'luoyang/peony': ('Ibu Kota Peony', 'Ribuan bunga peony yang mekar setiap bulan April menjadikan Luoyang sebagai \'ibu kota peony\'.'),
  'luoyang/whitehorse': ('Kuil Kuda Putih', 'Didirikan pada tahun 68 Masehi, kuil ini dianggap sebagai biara Buddha pertama di Tiongkok.'),
  'luoyang/capital': ('Ibu Kota Kuno', 'Sebagai ibu kota dari tiga belas dinasti, Luoyang merupakan salah satu pusat peradaban Tiongkok.'),
  'shantou/gongfutea': ('Teh Gongfu', 'Diseduh secara seremonial dalam cangkir kecil, teh gongfu khas Chaoshan merupakan seni keramah-tamahan.'),
  'shantou/beefpot': ('Hotpot Daging Sapi', 'Hotpot khas Chaoshan yang menyajikan irisan daging sapi segar yang dimasak dalam hitungan detik sangatlah populer.'),
  'shantou/opera': ('Opera Teochew', 'Opera Teochew yang berusia 600 tahun dikenal karena nyanyiannya yang lembut dan kostumnya yang bersulam indah.'),
  'shantou/harbor': ('Pelabuhan Shantou', 'Sebagai kampung halaman banyak perantau Tionghoa, pelabuhan ini merupakan gerbang perdagangan maritim yang bersejarah.'),
  'baoding/mansion': ('Kediaman Gubernur', 'Kantor pemerintahan provinsi tertinggi dari era Dinasti Qing ini merupakan aula pemerintahan yang terpelihara dengan baik.'),
  'baoding/donkeyburger': ('Burger Keledai', 'Daging keledai berbumbu yang disajikan di dalam roti pipih renyah merupakan jajanan khas daerah ini.'),
  'baoding/balls': ('Bola Kesehatan', 'Tradisi menggerakkan bola logam di telapak tangan untuk melatih otot tangan telah dilakukan selama berabad-abad.'),
  'baoding/reeds': ('Rawa Baiyangdian', 'Lahan basah terbesar di wilayah utara ini merupakan surga bagi burung dengan pemandangan ilalang dan bunga teratai.'),
  'jilin/rime': ('Bunga Es', 'Lapisan es putih yang menyelimuti pepohonan di tepi Sungai Songhua merupakan salah satu dari empat keajaiban alam Tiongkok.'),
  'jilin/snowboard': ('Resor Ski', 'Dengan salju yang tebal dan musim dingin yang panjang, kota ini menjadi salah satu destinasi ski terbaik di wilayah utara.'),
  'jilin/meteorite': ('Museum Meteorit', 'Museum ini memamerkan meteorit berbatu terbesar di dunia yang jatuh ke bumi pada tahun 1976.'),
  'jilin/skate': ('Sungai Songhua Beku', 'Saat musim dingin, Sungai Songhua yang membeku berubah menjadi gelanggang es yang ramai oleh pemain seluncur dan pejalan kaki.'),
  'ordos/khan': ('Mausoleum Genghis Khan', 'Mausoleum megah yang menghormati pahlawan padang rumput Genghis Khan ini merupakan pusat kebudayaan Mongol.'),
  'ordos/cashmere': ('Kasmir', 'Kasmir yang ditenun dari wol kambing Erdos telah membawa kota ini ke kancah industri tekstil dunia.'),
  'ordos/sanddune': ('Bukit Pasir Bernyanyi', 'Bukit pasir raksasa yang mengeluarkan suara saat diseluncuri ini merupakan destinasi wisata favorit di Gurun Kubuqi.'),
  'ordos/yurt': ('Yurt Mongolia', 'Tenda kain putih yang didirikan di padang rumput luas ini melambangkan gaya hidup nomaden masyarakat setempat.'),
  'jining/confucius': ('Kuil Konfusius', 'Terletak di Qufu, kompleks kuil, kediaman, dan makam filsuf Konfusius ini telah terdaftar sebagai Situs Warisan Dunia UNESCO.'),
  'jining/barge': ('Kanal Besar', 'Sebagai pelabuhan sibuk di jalur Kanal Beijing-Hangzhou, Jining dulunya merupakan pusat kebudayaan kanal yang penting.'),
  'jining/sword': ('Pahlawan Liangshan', 'Sebanyak 108 pahlawan pemberontak dari kisah klasik \'Batas Air\' berkumpul di perbukitan rawa ini.'),
  'jining/fishnet': ('Danau Weishan', 'Di danau teratai terbesar di utara ini, para nelayan menebar jala dengan cara tradisional yang telah diwariskan turun-temurun.'),
  'langfang/culture': ('Pusat Budaya Jalur Sutra', 'Pusat kebudayaan modern yang megah ini mengumpulkan berbagai kesenian dari Jalur Sutra di bawah satu atap.'),
  'langfang/furniture': ('Kota Mebel', 'Wilayah Xianghe di dekatnya merupakan salah satu pusat produksi dan perdagangan furnitur terbesar di Tiongkok.'),
  'langfang/tunnel': ('Terowongan Perang Kuno', 'Jaringan terowongan militer bawah tanah berusia ribuan tahun ini dulunya berfungsi sebagai garis pertahanan perbatasan.'),
  'langfang/themepark': ('Taman \'Kota No. 1\'', 'Taman hiburan luas yang merekonstruksi suasana kota bertembok kuno ini menjadi destinasi wisata keluarga yang populer.'),
  'yancheng/salt': ('Kota Garam', 'Namanya berarti \'benteng garam\', karena selama berabad-abad Yancheng menjadi pusat produksi garam di Tiongkok.'),
  'yancheng/crane': ('Bangau Mahkota Merah', 'Lahan basah pesisir ini merupakan tempat musim dingin terbesar di dunia bagi bangau mahkota merah liar.'),
  'yancheng/elk': ('Rusa Père David', 'Sempat punah di alam liar, populasi rusa milu kini berhasil dikembangbiakkan kembali di kawasan lahan basah ini.'),
  'yancheng/wetland': ('Lahan Basah Pesisir', 'Kawasan pasang surut yang terdaftar dalam situs warisan dunia UNESCO ini menjadi persinggahan global bagi burung migran.'),
  'huzhou/brush': ('Kuas Hu', 'Kuas Hu, yang dikenal sebagai salah satu dari \'empat harta\' kaligrafi Tiongkok, diproduksi di kota ini.'),
  'huzhou/bamboo': ('Hutan Bambu Anji', 'Hutan bambu hijau yang membentang luas ini pernah menjadi inspirasi film dan memberikan kesejukan udara di sekitarnya.'),
  'huzhou/silkworm': ('Ulat Sutra', 'Pesisir selatan Danau Tai telah menjadi pusat industri sutra murbei selama ribuan tahun.'),
  'huzhou/whitetea': ('Teh Putih Anji', 'Dengan daun berwarna pucat dan rasa yang manis, teh putih Anji termasuk salah satu jenis teh paling langka di Tiongkok.'),
  'quzhou/go': ('Go (Weiqi)', 'Dikenal melalui legenda Gunung Lanke, kota ini dihormati sebagai tanah kelahiran permainan Go.'),
  'quzhou/peaks': ('Gunung Jianglang', 'Tiga pilar batu raksasa yang menjulang ke langit membentuk lanskap unik warisan dunia UNESCO.'),
  'quzhou/ponkan': ('Jeruk Ponkan Quzhou', 'Jeruk ponkan dengan kulit yang manis ini merupakan buah khas musim dingin dari perbukitan yang sejuk.'),
  'quzhou/cake': ('Roti Wijen Panggang', 'Roti pipih wijen renyah yang dipanggang di dinding oven merupakan menu sarapan klasik masyarakat setempat.'),
  'huainan/tofu': ('Tempat Kelahiran Tahu', 'Ditemukan di Gunung Bagong 2.000 tahun yang lalu, tahu menyebar ke seluruh dunia dari tempat ini.'),
  'huainan/coalmine': ('Kota Batu Bara', 'Kaya akan cadangan batu bara, Huainan menjadi basis energi utama di Tiongkok bagian timur.'),
  'huainan/oldtown': ('Kota Tua Shou', 'Tembok kota era Dinasti Song yang terjaga utuh merupakan contoh langka dari desain pertahanan kuno.'),
  'huainan/classic': ('Huainanzi', 'Karya klasik filsafat yang disusun oleh Pangeran Liu An ini ditulis di tanah Huainan.'),
  'jingdezhen/porcelain': ('Ibu Kota Porselen', 'Memproduksi porselen kekaisaran selama seribu tahun, kota ini dikenal sebagai ibu kota porselen dunia.'),
  'jingdezhen/kiln': ('Tungku Kuno', 'Tungku berbentuk naga yang dibakar dengan kayu tetap melestarikan seni tradisional pembuatan porselen.'),
  'jingdezhen/bluewhite': ('Porselen Biru Putih', 'Porselen putih dengan motif biru kobalt merupakan ciri khas kota ini yang mendunia.'),
  'jingdezhen/painting': ('Lukisan Porselen', 'Porselen yang dilukis dengan kuas halus oleh para seniman ahli sangat dihargai layaknya karya seni lukis.'),
  'jian/jinggang': ('Pegunungan Jinggang', 'Pegunungan berkabut yang menjadi basis revolusi pertama ini merupakan pusat wisata sejarah merah.'),
  'jian/torch': ('Percikan Revolusi', 'Tanah yang melahirkan semboyan \'satu percikan api dapat membakar padang rumput\' ini merupakan situs peringatan bersejarah.'),
  'jian/academy': ('Akademi Bailuzhou', 'Akademi berusia seribu tahun di sebuah pulau Sungai Gan ini telah mendidik banyak cendekiawan kekaisaran.'),
  'jian/pine': ('Pinus Jinggang', 'Pohon pinus merah yang tumbuh menembus kabut melambangkan semangat pegunungan dan ketangguhan.'),
  'nanping/wuyi': ('Pegunungan Wuyi', 'Pegunungan yang terdaftar dalam situs warisan dunia UNESCO ini merupakan perpaduan menawan antara tebing merah, ngarai hijau, serta kekayaan alam dan budaya.'),
  'nanping/rocktea': ('Teh Batu', 'Teh oolong \'Big Red Robe\' yang tumbuh di celah tebing ini termasuk salah satu teh termahal di dunia.'),
  'nanping/bambooraft': ('Rakit Sembilan Kelokan', 'Menyusuri Sungai Sembilan Kelokan dengan rakit bambu menawarkan pengalaman meluncur di antara tebing-tebing batu yang megah.'),
  'nanping/scholar': ('Zhu Xi', 'Zhu Xi, tokoh pendiri Neo-Konfusianisme, pernah mengajar dan menyebarkan ilmunya di kaki pegunungan ini.'),
  'shenzhen/skyscraper': ('Pencakar Langit', 'Hutan beton pencakar langit yang tumbuh dari desa nelayan dalam 40 tahun ini menjadi simbol keajaiban reformasi Tiongkok.'),
  'shenzhen/chip': ('Kota Teknologi', 'Berkat pasar elektronik Huaqiangbei dan berbagai raksasa teknologi, Shenzhen dijuluki sebagai \'Lembah Silikon Tiongkok\'.'),
  'shenzhen/miniature': ('Window of the World', 'Taman hiburan yang menampilkan miniatur berbagai landmark terkenal dunia ini merupakan salah satu ikon kota Shenzhen.'),
  'shenzhen/mangrove': ('Teluk Shenzhen', 'Kawasan teluk yang dipenuhi hutan bakau ini menjadi tempat perlindungan bagi burung migran dan burung kuntul.'),
  'xian/terracotta': ('Prajurit Terakota', 'Ribuan patung prajurit tanah liat yang menjaga makam Kaisar Qin ini sering disebut sebagai keajaiban dunia kedelapan.'),
  'xian/citywall': ('Tembok Kota Xi\'an', 'Tembok kota dari era Dinasti Ming yang paling terawat di Tiongkok ini dapat dijelajahi dengan bersepeda di sepanjang bentengnya.'),
  'xian/drumtower': ('Menara Lonceng', 'Menara lonceng peninggalan Dinasti Ming yang terletak tepat di pusat kota ini menandai jantung dari ibu kota kuno tersebut.'),
  'xian/roujiamo': ('Roujiamo', 'Daging berbumbu yang disajikan di dalam roti pipih renyah ini dikenal sebagai burger asli dari Jalur Sutra.'),
  'suzhou/garden': ('Taman Klasik Suzhou', 'Taman-taman yang dirancang dengan indah menggunakan bebatuan, kolam, dan paviliun ini telah diakui sebagai situs warisan dunia UNESCO.'),
  'suzhou/watertown': ('Kota Air', 'Dengan kanal-kanal, jembatan batu, dan rumah-rumah bercat putih, Suzhou dijuluki sebagai \'Venesia dari Timur\'.'),
  'suzhou/embroidery': ('Sulam Su', 'Sulam sutra dua sisi merupakan kerajinan tangan tradisional khas Suzhou yang telah berusia ribuan tahun.'),
  'suzhou/kunqu': ('Opera Kunqu', 'Opera Kunqu yang anggun, yang dianggap sebagai induk dari semua opera Tiongkok, lahir di kota ini.'),
  'kunming/stoneforest': ('Hutan Batu', 'Pilar-pilar batu kapur raksasa yang terbentuk selama jutaan tahun membentuk labirin batu yang menakjubkan.'),
  'kunming/springcity': ('Kota Musim Semi', 'Dengan iklim yang sejuk sepanjang tahun, Kunming dijuluki sebagai \'kota musim semi\' tempat bunga-bunga mekar abadi.'),
  'kunming/seagull': ('Burung Camar Kepala Hitam', 'Setiap musim dingin, ribuan burung camar dari Siberia datang dan memutihkan tepian danau.'),
  'kunming/ricenoodle': ('Mi Crossing-Bridge', 'Mi beras tipis yang disajikan dengan kaldu panas di meja makan ini merupakan hidangan khas Yunnan.'),
  'jinan/spring': ('Kota Mata Air', 'Tujuh puluh dua mata air terkenal yang menyembur dari tanah memberikan Jinan julukan \'kota mata air\'.'),
  'jinan/daminglake': ('Danau Daming', 'Dikelilingi oleh pohon dedalu dan bunga teratai, danau kota ini dialiri oleh air dari mata air setempat.'),
  'jinan/buddhamountain': ('Gunung Seribu Buddha', 'Dengan ratusan patung Buddha yang dipahat di lerengnya, gunung ini menjadi tempat ziarah yang sakral.'),
  'jinan/poet': ('Penyair Li Qingzhao', 'Penyair wanita terhebat di Tiongkok, Li Qingzhao, lahir di kota mata air ini.'),
  'ningbo/library': ('Paviliun Tianyi', 'Paviliun Tianyi yang berusia 450 tahun merupakan perpustakaan pribadi tertua yang masih ada di Asia.'),
  'ningbo/port': ('Pelabuhan Kargo', 'Ningbo-Zhoushan merupakan pelabuhan tersibuk di dunia berdasarkan tonase kargo.'),
  'ningbo/tangyuan': ('Tangyuan', 'Bola ketan berisi wijen yang disebut \'tangyuan\' adalah hidangan manis khas kota ini.'),
  'ningbo/seafood': ('Hidangan Laut', 'Ikan croaker kuning dan kepiting dari Laut Tiongkok Timur menjadi bahan utama dalam kuliner lokal.'),
  'shijiazhuang/bridge': ('Jembatan Zhaozhou', 'Jembatan lengkung batu berusia 1.400 tahun ini adalah jembatan lengkung terbuka tertua di dunia.'),
  'shijiazhuang/clifftemple': ('Gunung Cangyan', 'Kuil jembatan yang tergantung di antara tebing ini telah menjadi latar belakang bagi banyak film.'),
  'shijiazhuang/redbase': ('Basis Xibaipo', 'Desa tempat perencanaan Tiongkok Baru ini merupakan destinasi sakral dalam wisata sejarah revolusioner.'),
  'shijiazhuang/pharma': ('Kota Farmasi', 'Sebagai salah satu produsen obat terbesar di Tiongkok, kota ini menjadi pusat produksi antibiotik utama.'),
  'taiyuan/jincitemple': ('Kuil Jinci', 'Dengan patung dan mata air berusia tiga ribu tahun, Jinci adalah taman kuil paling anggun di Tiongkok utara.'),
  'taiyuan/coalcart': ('Negeri Batu Bara', 'Cadangan batu bara Shanxi menjadi sumber energi utama Tiongkok, dan Taiyuan adalah ibu kota dari kekayaan tersebut.'),
  'taiyuan/vinegar': ('Cuka Hitam', 'Cuka hitam yang telah difermentasi lama merupakan elemen rasa asam yang esensial dalam kuliner Shanxi.'),
  'taiyuan/twinpagoda': ('Pagoda Kembar', 'Dua pagoda segi delapan dari Dinasti Ming yang berdiri berdampingan ini menjadi ikon kebanggaan kota.'),
  'hohhot/lamatemple': ('Kuil Dazhao', 'Terkenal dengan patung Buddha peraknya, biara Buddha Tibet ini merupakan pusat spiritual kota Hohhot.'),
  'hohhot/dairy': ('Ibu Kota Susu', 'Merek-merek susu terbesar di Tiongkok lahir di sini, sehingga kota ini dijuluki sebagai ibu kota susu.'),
  'hohhot/wrestling': ('Gulat Mongolia', 'Gulat Bökh, yang menjadi sorotan utama dalam festival Naadam, merupakan ajang unjuk kekuatan khas padang rumput.'),
  'hohhot/prairie': ('Padang Rumput', 'Di luar kota terhampar padang rumput Mongolia yang hijau, lengkap dengan kuda dan kawanan ternak.'),
  'sanya/resortbeach': ('Pantai Tropis', 'Pasir putih halus dan air biru kehijauan di Teluk Yalong menjadikan tempat ini sebagai Hawaii-nya Tiongkok.'),
  'sanya/guanyin': ('Patung Guanyin', 'Menjulang setinggi 108 meter di atas laut, patung Guanyin ini termasuk salah satu figur dewi tertinggi di dunia.'),
  'sanya/diving': ('Menyelam', 'Dengan air yang hangat, jernih, dan terumbu karang yang indah, Sanya adalah surga menyelam di Tiongkok.'),
  'sanya/coconutdrink': ('Kelapa', 'Air kelapa segar dari kebun tropis merupakan minuman penyegar yang paling dicari di pulau ini.'),
  'yangzhou/slenderlake': ('Danau Slender West', 'Dengan pemandangan pohon dedalu dan jembatan putih, danau yang ramping ini tampak seanggun lukisan.'),
  'yangzhou/friedrice': ('Nasi goreng Yangzhou', 'Nasi goreng berwarna keemasan dengan udang dan telur ini merupakan hidangan klasik yang mendunia.'),
  'yangzhou/morningtea': ('Morning tea', 'Menikmati sarapan elegan berupa bakpao dan teh merupakan ritual khas masyarakat Yangzhou.'),
  'yangzhou/gegarden': ('Taman Ge', 'Taman bambu yang menampilkan replika empat musim melalui bebatuan ini adalah mahakarya desain klasik Tiongkok.'),
  'weihai/navalisland': ('Pulau Liugong', 'Sebagai pangkalan Armada Beiyang, pulau ini menjadi saksi sejarah angkatan laut Tiongkok modern.'),
  'weihai/swan': ('Danau Angsa', 'Setiap musim dingin, ratusan angsa whooper dari Siberia datang bermigrasi ke laguna pesisir ini.'),
  'weihai/seacucumber': ('Teripang', 'Tumbuh di perairan yang dingin dan bersih, teripang menjadi hidangan laut paling berharga di kota ini.'),
  'weihai/cape': ('Tanjung Tiongkok', 'Tanjung paling timur di Tiongkok ini merupakan tempat pertama matahari menyapa daratan Tiongkok.'),
  'handan/taichi': ('Tai Chi', 'Kota Guangfu, tempat kelahiran aliran Yang dan Wu, dikenal sebagai rumah bagi taijiquan.'),
  'handan/congtai': ('Teras Congtai', 'Teras tanah dari zaman Kerajaan Zhao kuno ini telah menyaksikan lebih dari 2.000 tahun sejarah.'),
  'handan/idiom': ('Kota Idiom', 'Lebih dari 1.500 idiom Tiongkok lahir di sini, menjadikan Handan dijuluki sebagai \'kota idiom\'.'),
  'handan/ciporcelain': ('Keramik Cizhou', 'Keramik Cizhou dengan motif hitam di atas putih merupakan karya klasik keramik rakyat Tiongkok.'),
  'daqing/oilpump': ('Ladang minyak', 'Ladang minyak terbesar di Tiongkok ini dipenuhi dengan mesin pompa minyak yang bergerak naik-turun.'),
  'daqing/oilworker': ('Iron Man', 'Kegigihan pahlawan pekerja minyak Wang Jinxi menjadi semangat pendiri kota ini.'),
  'daqing/reedlake': ('Lahan basah', 'Danau luas yang ditumbuhi alang-alang di antara sumur minyak menjadi habitat bagi burung bangau dan angsa.'),
  'daqing/hotspring': ('Pemandian air panas', 'Air mineral panas dari bawah tanah menawarkan relaksasi yang menenangkan di tengah dinginnya wilayah utara.'),
  'zibo/bbq': ('Sate Zibo', 'Sate yang dipanggang di atas anglo kecil dan dibungkus dengan panekuk tipis ini menjadi tren kuliner yang populer di seluruh Tiongkok.'),
  'zibo/cuju': ('Cuju', 'Cuju, bentuk sepak bola tertua di dunia, dimainkan di ibu kota kuno Qi, yaitu Linzi.'),
  'zibo/ceramic': ('Keramik Zibo', 'Dengan tungku pembakaran berusia ribuan tahun, kota ini menjadi pusat keramik di Tiongkok bagian utara.'),
  'zibo/glass': ('Liuli', 'Liuli adalah kerajinan kaca berwarna buatan tangan yang memancarkan keindahan saat terkena cahaya.'),
  'taian/mounttai': ('Gunung Tai', 'Sebagai yang utama dari Lima Gunung Suci, Gunung Tai adalah puncak paling sakral tempat para kaisar memberikan persembahan kepada langit.'),
  'taian/sunrise': ('Matahari Terbit di Puncak', 'Menyaksikan matahari terbit di atas lautan awan adalah hadiah utama bagi mereka yang mendaki Gunung Tai.'),
  'taian/stonesteps': ('Anak Tangga Batu', 'Sebanyak 7.000 anak tangga batu menuju puncak menjadi ujian fisik bagi para peziarah.'),
  'taian/daitemple': ('Kuil Dai', 'Kuil megah di kaki gunung ini merupakan tempat para kaisar mempersiapkan diri sebelum melakukan ritual di Gunung Tai.'),
  'lianyungang/monkey': ('Gunung Huaguo', 'Gunung Huaguo, tempat tinggal Raja Kera dari kisah \'Perjalanan ke Barat\', terletak di sini.'),
  'lianyungang/seaport': ('Pelabuhan Laut', 'Gerbang laut timur Jalur Sutra ini merupakan titik akhir Pasifik dari jembatan kereta api Eurasia.'),
  'lianyungang/mountain': ('Gunung Yuntai', 'Dengan puncak yang curam dan hutan yang lebat, Yuntai merupakan gunung tertinggi di Provinsi Jiangsu.'),
  'lianyungang/crystal': ('Negeri Kristal', 'Wilayah Donghai di dekatnya menjadi tuan rumah bagi salah satu pasar kristal kuarsa terbesar di dunia.'),
  'maanshan/libai': ('Penyair Li Bai', 'Tempat peristirahatan terakhir dan makam penyair terbesar Tiongkok, Li Bai, berada di kota tepi sungai ini.'),
  'maanshan/steel': ('Kota Baja', 'Pabrik baja Magang menjadikan kota ini sebagai salah satu basis industri besi dan baja utama di Tiongkok.'),
  'maanshan/rivercliff': ('Tebing Caishiji', 'Tebing yang menjorok ke Sungai Yangtze ini merupakan latar puitis dari legenda penyair Li Bai.'),
  'maanshan/moonwine': ('Bulan dan Anggur', 'Bulan dan anggur yang sering muncul dalam puisi Li Bai masih dirayakan dalam festival di tepi sungai.'),
  'longyan/tulou': ('Tulou Yongding', 'Rumah benteng berbentuk bulat milik suku Hakka ini merupakan situs warisan dunia UNESCO yang tersebar di perbukitan.'),
  'longyan/redmeeting': ('Pertemuan Gutian', 'Pertemuan bersejarah yang menentukan arah Tentara Merah ini diselenggarakan di desa tersebut.'),
  'longyan/hakka': ('Budaya Hakka', 'Suku Hakka, para pendatang dari utara, tetap melestarikan bahasa dan kuliner mereka di perbukitan ini.'),
  'longyan/mountain': ('Gunung Guanzhi', 'Dengan tebing merah dan kolam yang jernih, gunung ini merupakan permata alam di Fujian bagian selatan.'),
  'sanming/danxia': ('Danxia Taining', 'Sebagai geopark UNESCO, kawasan dengan tebing dan ngarai merah ini menyerupai labirin batu yang jatuh dari langit.'),
  'sanming/shaxian': ('Camilan Sha County', 'Dengan pangsit dan mi campur yang terjangkau, camilan khas Sha County telah tersebar ke seluruh penjuru Tiongkok.'),
  'sanming/forest': ('Ibu Kota Hijau', 'Sebagai kota dengan tutupan hutan terluas di Tiongkok, Sanming menawarkan udara bersih dan pegunungan yang asri.'),
  'sanming/goldenlake': ('Danau Emas', 'Terbentang di antara tebing-tebing Danxia, danau ini dapat dijelajahi dengan menggunakan perahu.'),
  'ningde/mudflat': ('Dataran Lumpur Xiapu', 'Dataran pasang surut yang berkilauan dan terus berubah mengikuti laut ini menjadi salah satu pesisir yang paling banyak difoto di dunia.'),
  'ningde/whitetea': ('Teh Putih Fuding', 'Dibuat dari kuncup teh yang halus, teh putih ini semakin berharga seiring bertambahnya usia penyimpanan.'),
  'ningde/taimu': ('Gunung Taimu', 'Dengan puncak granit dan gua-gua di atas laut, gunung ini dijuluki sebagai negeri dongeng di tepi laut.'),
  'ningde/croaker': ('Ikan Croaker Kuning', 'Ikan croaker kuning besar yang dibudidayakan di teluk-teluk terlindung merupakan harta karun laut kota ini.'),
  'shaoguan/redcliff': ('Gunung Danxia', 'Gunung batu merah yang menjadi asal nama bentang alam Danxia ini terkenal dengan pilar-pilar batu alaminya.'),
  'shaoguan/chantemple': ('Kuil Nanhua', 'Sebagai tempat Huineng, Patriark Keenam Buddhisme Chan, kuil ini menjadi pusat suci bagi aliran tersebut.'),
  'shaoguan/ancestor': ('Zhuji Lane', 'Lorong ini merupakan tempat asal jutaan warga Tiongkok selatan yang menelusuri jejak leluhur mereka.'),
  'shaoguan/yaodance': ('Suku Yao', 'Suku Yao yang tinggal di desa pegunungan dikenal dengan pakaian adat yang penuh warna dan tarian gendang mereka.'),
  'zhanjiang/oyster': ('Tiram Zhanjiang', 'Tiram gemuk yang tumbuh di perairan selatan yang hangat ini biasanya dibakar di atas arang untuk disajikan di meja makan.'),
  'zhanjiang/navy': ('Pangkalan Angkatan Laut', 'Sebagai markas Armada Laut Selatan, pelabuhan dalam ini berfungsi sebagai gerbang laut selatan negara tersebut.'),
  'zhanjiang/mangrove': ('Hutan Mangrove', 'Hutan mangrove terbesar di Tiongkok ini menjadi tempat perlindungan bagi burung bangau dan kepiting di perairan pasang surutnya.'),
  'zhanjiang/donghai': ('Pulau Donghai', 'Dengan pantai yang panjang dan angin yang stabil, pulau ini menjadi destinasi favorit untuk berjemur dan berselancar.'),
  'maoming/lychee': ('Ibu Kota Leci', 'Sebagai produsen leci terbesar di Tiongkok, Maoming adalah daerah yang dulunya mengirimkan buah leci untuk para kaisar.'),
  'maoming/refinery': ('Pusat Petrokimia', 'Salah satu kilang minyak terbesar di Tiongkok selatan ini menjadi penggerak utama kekuatan industri kota tersebut.'),
  'maoming/ladyxian': ('Lady Xian', 'Lady Xian, pahlawan wanita yang menyatukan wilayah selatan, telah dihormati oleh masyarakat setempat selama seribu tahun.'),
  'maoming/seaside': ('Pantai', 'Dijuluki sebagai \'Pantai Nomor 1 Tiongkok\', pesisir panjang ini menawarkan hamparan pasir emas bagi keluarga.'),
  'zhaoqing/sevenstar': ('Seven Star Crags', 'Tujuh tebing batu kapur yang menjulang dari danau ini sering dijuluki sebagai \'Guilin-nya Guangdong\'.'),
  'zhaoqing/inkstone': ('Batu Tinta Duan', 'Batu tinta Duan, salah satu dari empat harta karun kaligrafi, telah diukir di tempat ini selama seribu tahun.'),
  'zhaoqing/dinghu': ('Gunung Dinghu', 'Cagar alam pertama di Tiongkok dengan hutan hujan lebat dan air terjun ini merupakan \'bar oksigen\' alami.'),
  'zhaoqing/songwall': ('Tembok Kota Song', 'Tembok era Dinasti Song yang terpelihara dengan baik ini mengelilingi kota tua Zhaoqing dengan jejak sejarah.'),
  'huizhou/westlake': ('Danau Barat Huizhou', 'Danau yang dicintai oleh penyair Su Shi ini bagaikan puisi yang terlukis melalui pepohonan dedalu dan jalan lintasnya.'),
  'huizhou/luofu': ('Gunung Luofu', 'Dikenal sebagai gunung para petapa Tao dan tanaman obat, tempat ini merupakan salah satu puncak suci utama di wilayah selatan.'),
  'huizhou/alchemy': ('Alkimia Ge Hong', 'Tabib sekaligus ahli alkimia Ge Hong menulis dasar-dasar pengobatan tradisional saat bermukim di gunung ini.'),
  'huizhou/xunliao': ('Teluk Xunliao', 'Dengan air yang jernih dan pasir yang lembut, teluk ini menjadi resor tepi pantai yang tenang di pesisir selatan.'),
  'meizhou/weilongwu': ('Ibu Kota Hakka', 'Sebagai ibu kota Hakka dunia, Meizhou terkenal dengan rumah tradisional weilongwu yang berbentuk tapal kuda.'),
  'meizhou/saltchicken': ('Ayam Panggang Garam', 'Ayam khas Hakka yang dimasak dengan cara dikubur dalam garam panas ini dikenal karena tekstur dagingnya yang sangat lembut.'),
  'meizhou/football': ('Kota Sepak Bola', 'Dianggap sebagai tempat lahirnya sepak bola Tiongkok, kota ini telah melahirkan banyak pemain bintang selama beberapa generasi.'),
  'meizhou/plum': ('Bunga Plum', 'Kota yang namanya berarti \'plum\' ini akan dipenuhi dengan keindahan bunga plum yang bermekaran saat musim dingin.'),
  'jiangmen/diaolou': ('Kaiping Diaolou', 'Menara benteng bertingkat yang dibangun oleh para perantau yang kembali ke kampung halaman ini telah terdaftar sebagai Situs Warisan Dunia UNESCO.'),
  'jiangmen/qiaoxiang': ('Kampung Halaman Perantau Tionghoa', 'Sebagai kampung halaman bagi jutaan perantau Tionghoa, kota ini memadukan ini memadukan kebudayaan Timur dan Barat dengan harmonis.'),
  'jiangmen/chenpi': ('Kulit Jeruk Kering', 'Kulit jeruk Xinhui yang telah disimpan lama merupakan rempah sekaligus obat tradisional yang sangat berharga.'),
  'jiangmen/birds': ('Surga Burung', 'Sebuah hutan yang tumbuh dari satu pohon beringin raksasa ini menjadi habitat bagi puluhan ribu burung bangau.'),
  'yangjiang/knife': ('Ibu Kota Pisau', 'Sebagian besar pisau dapur di Tiongkok ditempa di sini melalui tradisi pandai besi yang telah berlangsung selama berabad-abad.'),
  'yangjiang/shipwreck': ('Bangkai Kapal Nanhai No. 1', 'Kapal era Dinasti Song dari Jalur Sutra Maritim ini dipamerkan bersama harta karunnya di sebuah museum bawah air.'),
  'yangjiang/hailing': ('Pulau Hailing', 'Dengan pantai yang cerah dan ombak yang indah, pulau ini menjadi resor tepi laut favorit di Provinsi Guangdong.'),
  'yangjiang/kite': ('Kota Layang-layang', 'Sebagai salah satu ibu kota layang-layang di Tiongkok selain Weifang, kota ini selalu menghiasi langit musim gugur dengan berbagai layang-layang.'),
  'qingyuan/rafting': ('Ibu Kota Arung Jeram', 'Berkat aliran sungai pegunungan yang deras, Qingyuan dijuluki sebagai pusat arung jeram di Tiongkok.'),
  'qingyuan/chicken': ('Ayam Qingyuan', 'Ras ayam lokal dengan tulang halus dan daging yang gurih ini merupakan hidangan paling dicari di meja makan masyarakat Kanton.'),
  'qingyuan/hotspring': ('Pemandian Air Panas', 'Mata air mineral panas dari lembah pegunungan menjadi destinasi utama untuk liburan akhir pekan.'),
  'qingyuan/yaoterrace': ('Terasering Sawah Yao', 'Terasering yang dipahat di lereng bukit oleh suku Yao di Liannan merupakan bukti kerja keras selama berabad-abad.'),
  'chaozhou/guangjibridge': ('Jembatan Guangji', 'Jembatan kuno dengan bagian tengah yang dapat dibuka untuk lalu lintas kapal ini merupakan salah satu dari empat jembatan paling terkenal di Tiongkok.'),
  'chaozhou/woodcarving': ('Ukiran Kayu Lapis Emas', 'Ukiran kayu berlapis emas dengan detail berlapis-lapis memberikan kesan megah pada kuil-kuil setempat.'),
  'chaozhou/chaoxiu': ('Sulam Chaozhou', 'Dengan teknik sulaman benang emas yang menonjol, sulam Chaozhou dikenal sebagai salah satu kerajinan paling mewah di Tiongkok selatan.'),
  'chaozhou/kaiyuan': ('Kuil Kaiyuan', 'Kuil berusia 1.200 tahun dengan halaman bergaya Dinasti Tang yang tenang ini merupakan pusat spiritual kota.'),
  'jieyang/citygate': ('Gerbang Jinxian', 'Menara gerbang kayu yang anggun di atas sungai ini merupakan simbol bersejarah yang masih bertahan dari Jieyang masa lampau.'),
  'jieyang/jade': ('Ibu Kota Giok', 'Kota Yangmei merupakan salah satu pusat perdagangan dan pengukiran giok terbesar di Tiongkok.'),
  'jieyang/jieyanglou': ('Menara Jieyang', 'Menara raksasa dengan atap tradisional ini merupakan monumen modern bagi kebudayaan Chaoshan.'),
  'jieyang/beefbroth': ('Sup Daging Sapi Chaoshan', 'Daging sapi segar yang dicelup ke dalam kaldu bening merupakan hidangan kebanggaan di wilayah ini.'),
  'yunfu/marble': ('Kerajaan Batu', 'Sebagai pusat industri marmer dan pengolahan batu, Yunfu mengekspor batu poles berkualitas ke seluruh dunia.'),
  'yunfu/patriarch': ('Patriark Keenam', 'Sebagai tempat kelahiran guru besar Chan, Huineng, wilayah ini disucikan oleh keberadaan Kuil Guoen.'),
  'yunfu/tianlu': ('Gunung Tianlu', 'Dengan puncak yang diselimuti awan dan kebun teh, gunung ini menjadi mahkota hijau bagi kota tersebut.'),
  'yunfu/xijiang': ('Sungai Xi', 'Cabang utama Sungai Mutiara yang menjadi jalur air besar di wilayah selatan ini mengalir melewati kota tersebut.'),
  'liuzhou/luosifen': ('Luosifen', 'Luosifen, mi siput dengan cita rasa asam pedas yang tajam, kini menjadi kuliner yang sangat populer di seluruh Tiongkok.'),
  'liuzhou/autocity': ('Kota Otomotif', 'Berkat kegemaran penduduknya terhadap mobil kota yang ringkas, Liuzhou menjadi salah satu basis industri otomotif terbesar di Tiongkok.'),
  'liuzhou/karst': ('Karst Sungai Liu', 'Perbukitan kapur dan kelokan sungai yang mengelilingi kota memberikan keindahan alami pada kota industri ini.'),
  'liuzhou/liuhou': ('Penyair Liu Zongyuan', 'Kenangan akan penyair sekaligus gubernur dari Dinasti Tang, Liu Zongyuan, diabadikan dalam sebuah kuil di taman kota.'),
  'wuzhou/gemstone': ('Ibu Kota Batu Permata', 'Sebagian besar batu permata buatan dunia diproduksi di bengkel-bengkel yang terletak di kota tepi sungai ini.'),
  'wuzhou/liubaotea': ('Teh Hitam Liubao', 'Teh hitam Liubao yang telah difermentasi merupakan minuman klasik yang dipercaya baik untuk pencernaan di wilayah selatan yang lembap.'),
  'wuzhou/turtlejelly': ('Guilinggao', 'Jeli herbal hitam yang sedikit pahit ini merupakan hidangan penutup yang menyegarkan saat cuaca panas.'),
  'wuzhou/dragonmother': ('Kuil Ibu Naga', 'Kuil yang didedikasikan untuk dewi sungai, Ibu Naga, ini merupakan pusat kepercayaan masyarakat setempat sejak zaman dahulu.'),
  'beihai/silverbeach': ('Pantai Perak', 'Dikenal sebagai pantai terbaik di bawah langit, pantai ini membentang luas dengan hamparan pasir putih yang berkilauan.'),
  'beihai/pearl': ('Kota Mutiara', 'Mutiara Laut Selatan dari Hepu telah lama dianggap sebagai mutiara terbaik sejak zaman kekaisaran.'),
  'beihai/weizhou': ('Pulau Weizhou', 'Pulau vulkanik termuda di Tiongkok ini menarik minat para penyelam dengan tebing hitam dan terumbu karangnya yang indah.'),
  'beihai/oldstreet': ('Jalan Tua', 'Bangunan kolonial beratap pilar yang berusia seabad ini menjaga sejarah pelabuhan Jalur Sutra Maritim tetap hidup.'),
  'qinzhou/nixingpottery': ('Tembikar Nixing', 'Tembikar Nixing, yang warnanya dapat berubah secara alami saat dibakar di tungku, merupakan salah satu dari empat kerajinan keramik ternama di Tiongkok.'),
  'qinzhou/dolphin': ('Lumba-lumba Putih', 'Lumba-lumba putih Tiongkok yang langka dan berenang di Teluk Sanniang merupakan simbol kebanggaan kota ini.'),
  'qinzhou/oysterfarm': ('Budidaya Tiram', 'Tiram raksasa yang dibudidayakan di teluk dangkal menjadikan Qinzhou sebagai ibu kota tiram di Tiongkok.'),
  'qinzhou/general': ('Jenderal Feng Zicai', 'Sebagai kampung halaman Jenderal Feng Zicai yang gagah berani mempertahankan perbatasan, kota ini penuh dengan kenangan kepahlawanan.'),
  'guigang/lotus': ('Kota Teratai', 'Dengan hamparan ladang teratai yang mekar sepanjang musim panas, Guigang dijuluki sebagai \'Kota Teratai\'.'),
  'guigang/uprising': ('Pemberontakan Jintian', 'Percikan pertama dari sejarah Pemberontakan Taiping yang mengguncang dunia bermula di tanah ini.'),
  'guigang/nanshan': ('Kuil Nanshan', 'Kuil gua berusia seribu tahun yang dipahat di bebatuan ini dihiasi dengan prasasti kekaisaran.'),
  'guigang/sugarcane': ('Tebu', 'Dataran sungai yang subur ini merupakan sumber manis bagi produksi gula terbesar di Tiongkok.'),
  'yulin/medicine': ('Pasar Obat Herbal', 'Pasar obat tradisional terbesar di Tiongkok Selatan ini mengumpulkan ribuan jenis tanaman penyembuh.'),
  'yulin/goldenpalace': ('Istana Yuntian', 'Istana budaya raksasa yang dilapisi emas ini memukau pengunjung dengan patung dan aula yang megah.'),
  'yulin/lychee': ('Kebun Leci', 'Leci manis yang tumbuh di perbukitan hangat adalah harta karun merah di pasar-pasar musim panas.'),
  'yulin/beef': ('Daging Sapi Yulin', 'Daging sapi berbumbu yang dikenal sebagai \'niuba\' merupakan camilan khas daerah ini yang sudah ada sejak lama.'),
  'baise/redbase': ('Pemberontakan Baise', 'Pemberontakan yang dipimpin oleh Deng Xiaoping muda ini menjadi titik balik penting dalam sejarah revolusi Tiongkok.'),
  'baise/sinkhole': ('Lubang Raksasa Leye', 'Gugusan lubang raksasa terbesar di dunia ini menyimpan hutan tersembunyi di kedalamannya.'),
  'baise/mango': ('Ibu Kota Mangga', 'Berkat lembahnya yang panas, Baise menjadi lokasi perkebunan mangga terbesar di Tiongkok.'),
  'baise/aluminum': ('Kota Aluminium', 'Kaya akan bauksit, kota ini menjadi basis industri aluminium utama di Tiongkok bagian selatan.'),
  'hechi/longevity': ('Bama, Desa Panjang Umur', 'Dengan penduduk yang berusia lebih dari seratus tahun, Bama dikenal dunia sebagai \'desa panjang umur\'.'),
  'hechi/folksong': ('Liu Sanjie', 'Legenda peri lagu Liu Sanjie terus hidup melalui tradisi lomba menyanyi bersahut-sahutan.'),
  'hechi/bronzedrum': ('Gendang Perunggu', 'Gendang perunggu sakral milik suku Zhuang dan masyarakat pegunungan paling banyak ditemukan di wilayah ini.'),
  'hechi/geopark': ('Geopark Karst', 'Dengan adanya lubang runtuhan, gua, dan sungai bawah tanah, kawasan ini merupakan surga bentang alam karst.'),
  'laibin/sugarcity': ('Kota Gula', 'Berkat hamparan ladang tebu yang luas, Laibin dijuluki sebagai \'kota gula Tiongkok\'.'),
  'laibin/yao': ('Suku Yao Dayao', 'Suku Yao di pegunungan Dayao, Jinxiu, yang terbagi ke dalam lima kelompok berbeda, merupakan kekayaan budaya yang berharga.'),
  'laibin/hongshui': ('Sungai Hongshui', 'Sungai Hongshui yang perkasa mengukir lembah-lembah dan menopang wilayah ini melalui bendungan serta pemandangan alamnya.'),
  'laibin/shengtang': ('Gunung Shengtang', 'Dengan lautan awan dan air terjunnya, gunung ini merupakan puncak tertinggi di pegunungan Dayao.'),
  'chongzuo/waterfall': ('Air Terjun Detian', 'Terletak di perbatasan Vietnam, Detian merupakan air terjun lintas negara terbesar di Asia.'),
  'chongzuo/langur': ('Lutung Kepala Putih', 'Hanya hidup di perbukitan kapur ini, lutung kepala putih yang langka termasuk salah satu monyet paling terancam punah di dunia.'),
  'chongzuo/rockart': ('Seni Cadas Huashan', 'Sosok-sosok berwarna merah yang dilukis di tebing Zuojiang sejak 2.000 tahun lalu ini telah terdaftar sebagai Situs Warisan Dunia UNESCO.'),
  'chongzuo/borderpass': ('Gerbang Persahabatan', 'Gerbang perbatasan bersejarah menuju Vietnam ini merupakan pintu gerbang darat Jalur Sutra selatan.'),
  'beijing/great-wall': ('Tembok Besar Tiongkok', 'Benteng terpanjang di dunia ini dibangun selama berabad-abad untuk menjaga perbatasan utara Tiongkok, dengan bagian Badaling di Beijing sebagai area yang paling sering dikunjungi.'),
  'beijing/temple': ('Kuil Surga', 'Kompleks sakral tempat kaisar dinasti Ming dan Qing berdoa demi panen yang melimpah, yang dikenal dengan atap bundar biru tiga tingkat tanpa paku.'),
  'beijing/pagoda': ('Pagoda Tianning', 'Pagoda bata 13 tingkat setinggi 57 meter dari dinasti Liao ini merupakan salah satu struktur tertua di Beijing yang menjadi saksi sejarah kota selama seribu tahun.'),
  'beijing/opera': ('Opera Beijing', 'Seni teater tradisional Tiongkok berusia 200 tahun yang memadukan nyanyian, dialog, bela diri, dan akrobat dengan riasan wajah (lianpu) yang melambangkan karakter tokohnya.'),
  'zunyi/huiyi': ('Konferensi Zunyi', 'Gedung tempat berlangsungnya pertemuan tahun 1935 ini menjadi titik balik sejarah revolusi Tiongkok.'),
  'zunyi/moutai': ('Kota Moutai', 'Diproduksi di kota tepi Sungai Chishui, Moutai adalah minuman keras baijiu legendaris yang dijuluki sebagai minuman nasional Tiongkok.'),
  'zunyi/loushan': ('Celah Loushan', 'Celah curam di pegunungan ini merupakan lokasi pertempuran bersejarah yang diabadikan dalam puisi terkenal Mao Zedong.'),
  'zunyi/chishui': ('Air Terjun Chishui', 'Air terjun yang mengalir dari tebing merah Danxia dan hutan bambu ini memenuhi lembah \'sungai merah\'.'),
  'liupanshui/coolcity': ('Kota Sejuk', 'Dengan suhu musim panas yang jarang melebihi 19°C, Liupanshui dikenal sebagai \'ibu kota sejuk Tiongkok\'.'),
  'liupanshui/coal': ('Lautan Batu Bara Barat Daya', 'Kekayaan cadangan batu bara menjadikan kota ini sebagai pusat energi utama di wilayah barat daya Tiongkok.'),
  'liupanshui/grassland': ('Padang Rumput Wumeng', 'Padang rumput dataran tinggi Wumeng yang luas dihiasi oleh kawanan kuda dan turbin angin.'),
  'liupanshui/kiwi': ('Kiwi Berinti Merah', 'Kiwi berinti merah yang tumbuh di dataran tinggi yang sejuk merupakan harta karun buah manis kebanggaan kota ini.'),
  'anshun/huangguoshu': ('Air Terjun Huangguoshu', 'Air terjun terbesar di Asia ini jatuh setinggi 77 meter dengan kabut yang sering membiaskan pelangi.'),
  'anshun/dixi': ('Opera Tanah Dixi', 'Dixi, yang dipentaskan di alun-alun desa dengan topeng prajurit kayu, dikenal sebagai \'fosil hidup opera Tiongkok\'.'),
  'anshun/batik': ('Seni Batik', 'Kain yang digambar dengan lilin dan dicelup warna nila oleh perempuan suku Buyi dan Miao adalah kerajinan khas Anshun.'),
  'anshun/tunpu': ('Desa Tunpu', 'Penduduk desa di bekas garnisun militer Dinasti Ming ini masih melestarikan pakaian dan dialek berusia 600 tahun.'),
  'bijie/azalea': ('Sabuk Azalea Ratusan Li', 'Lautan bunga azalea yang menyelimuti perbukitan setiap musim semi ini merupakan taman bunga alami terbesar di dunia.'),
  'bijie/zhijin': ('Gua Zhijin', 'Dengan hutan stalagmit raksasa, \'istana bawah tanah\' Zhijin merupakan gua paling spektakuler di Tiongkok.'),
  'bijie/caohai': ('Burung Bangau Caohai', 'Danau dangkal di Weining ini menjadi rumah musim dingin bagi burung bangau leher hitam yang langka.'),
  'bijie/potato': ('Ibu Kota Kentang', 'Kentang dataran tinggi menjadikan Bijie sebagai lumbung kentang Tiongkok, dengan kentang dari Weining yang terkenal di seluruh negeri.'),
  'qujing/rapeseed': ('Lautan Bunga Kanola Luoping', 'Setiap bulan Februari, ladang bunga kanola berwarna keemasan di Luoping menarik perhatian para peternak lebah dan fotografer.'),
  'qujing/ham': ('Ham Xuanwei', 'Diawetkan dengan garam selama berabad-abad, ham Xuanwei menjadi kebanggaan kuliner masyarakat Yunnan.'),
  'qujing/jiulong': ('Air Terjun Jiulong', 'Sepuluh tingkat air terjun di sungai \'Sembilan Naga\' ini membentuk rangkaian air terjun terindah di Tiongkok.'),
  'qujing/sandforest': ('Hutan Pasir Berwarna', 'Pilar-pilar pasir berwarna yang terbentuk akibat kikisan angin menciptakan taman pahatan alami di Luliang.'),
  'yuxi/fuxian': ('Danau Fuxian', 'Danau terdalam kedua di Tiongkok ini bagaikan cermin pegunungan dengan air yang sangat jernih.'),
  'yuxi/nieer': ('Komponis Nie Er', 'Sebagai kota kelahiran Nie Er, pencipta lagu kebangsaan Tiongkok, Yuxi menghormatinya dengan membangun taman musik dan monumen peringatan.'),
  'yuxi/chengjiang': ('Fosil Chengjiang', 'Situs warisan dunia UNESCO ini menyimpan lapisan fosil Kambrium berusia 530 juta tahun yang menunjukkan awal mula kehidupan hewan.'),
  'yuxi/kiln': ('Tungku Yuxi', 'Tungku kuno dari era Dinasti Yuan ini merupakan tempat kelahiran keramik biru-putih khas Yunnan.'),
  'dali/threepagodas': ('Tiga Pagoda', 'Berdiri megah di kaki Gunung Cangshan selama seribu tahun, ketiga pagoda anggun ini menjadi lambang kerajaan Dali kuno.'),
  'dali/erhai': ('Danau Erhai', 'Danau pegunungan berbentuk telinga ini menyuguhkan pemandangan indah perahu nelayan dan desa-desa di tepi danau.'),
  'dali/cangshan': ('Pegunungan Cangshan', 'Dengan sembilan belas puncak yang tertutup salju, Pegunungan Cangshan menjulang layaknya tirai hijau di belakang kota Dali.'),
  'dali/wind': ('Angin, Bunga, Salju, Bulan', 'Angin Xiaguan, bunga Shangguan, salju Cangshan, dan bulan Erhai adalah empat keindahan Dali yang puitis.'),
  'lijiang/oldtown': ('Kota Tua Lijiang', 'Kota warisan dunia UNESCO yang dipenuhi kanal dan rumah kayu beratap genteng ini merupakan pusat kebudayaan Naxi yang masih hidup.'),
  'lijiang/snowmountain': ('Gunung Salju Naga Giok', 'Puncak glasial setinggi 5.596 meter ini bersinar di atas kota layaknya seekor naga giok yang sedang tertidur.'),
  'lijiang/dongba': ('Aksara Dongba', 'Aksara piktografis milik pendeta Naxi ini merupakan satu-satunya aksara gambar yang masih digunakan di dunia.'),
  'lijiang/tigerleaping': ('Ngarai Lompatan Harimau', 'Ngarai yang konon dilompati seekor harimau dalam sekali lompatan ini merupakan salah satu ngarai terdalam di dunia.'),
  'lincang/dianhong': ('Teh Hitam Dianhong', 'Teh hitam pucuk emas asal Fengqing ini telah membawa nama Yunnan dikenal ke seluruh dunia.'),
  'lincang/wadrum': ('Gendang Kayu Wa', 'Gendang kayu sakral suku Wa bergema di desa-desa perbukitan saat tarian gendang ayun rambut berlangsung.'),
  'lincang/teatrees': ('Pohon Teh Kuno', 'Sebagai rumah bagi pohon teh liar berusia ribuan tahun, Lincang menjaga hutan tempat asal muasal teh.'),
  'lincang/lancang': ('Sungai Lancang', 'Sebagai hulu Sungai Mekong, Sungai Lancang mengalir ke selatan dan menerangi lembah-lembah dengan bendungan raksasanya.'),
  'puer/tea': ('Teh Pu\'er', 'Teh Pu\'er yang dipadatkan dan semakin nikmat seiring bertambahnya usia merupakan harta karun yang dinamai sesuai kota pegunungan ini.'),
  'puer/coffee': ('Ibu Kota Kopi Tiongkok', 'Lebih dari separuh produksi kopi Tiongkok tumbuh di lereng berkabut Pu\'er, membuat kota ini selalu harum aroma kopi.'),
  'puer/teahorse': ('Jalur Teh dan Kuda', 'Jalur kuno tempat karavan bagal membawa teh ke Tibet ini bermula dari Pu\'er dan mendaki hingga ke awan.'),
  'puer/peafowl': ('Merak Hijau', 'Hutan tropis yang menjadi tempat berlindung bagi merak hijau yang langka merupakan mahkota alam kota ini.'),
  'baoshan/volcano': ('Gunung Berapi Tengchong', 'Sembilan puluh tujuh kerucut vulkanik yang tidak aktif mengubah dataran Tengchong menjadi lanskap seperti permukaan bulan.'),
  'baoshan/rehai': ('Lembah Rehai', 'Di lembah \'Lautan Panas\' yang mendidih, geyser mengeluarkan uap dan telur dapat dimasak langsung di kolam mata air.'),
  'baoshan/heshun': ('Kota Heshun', 'Heshun, kota batu para pedagang perantau, menyimpan perpustakaan desa tertua di Tiongkok.'),
  'baoshan/gaoligong': ('Pegunungan Gaoligong', 'Dengan lembah kupu-kupu dan hutan hangatnya, Gaoligong menjadi gudang harta karun bagi berbagai spesies.'),
  'deyang/sanxingdui': ('Reruntuhan Sanxingdui', 'Topeng perunggu raksasa dengan mata menonjol mengungkap peradaban Shu yang misterius dari 3.000 tahun silam.'),
  'deyang/jiannanchun': ('Arak Jiannanchun', 'Jiannanchun merupakan baijiu asal Mianzhu yang pernah disajikan di istana Dinasti Tang dan telah disuling selama lima belas abad.'),
  'deyang/nianhua': ('Lukisan Tahun Baru Mianzhu', 'Lukisan kayu yang dilukis dengan tangan ini dipasang di ambang pintu untuk membawa keberuntungan dan warna pada perayaan Tahun Baru.'),
  'deyang/turbine': ('Ibu Kota Industri Berat', 'Sebagian besar turbin dan generator raksasa di Tiongkok diproduksi di bengkel-bengkel industri Deyang.'),
  'mianyang/libai': ('Kampung Halaman Li Bai', 'Li Bai, sang penyair abadi, tumbuh besar di antara pegunungan Jiangyou dan bait-bait puisinya masih bergema di tempat ini.'),
  'mianyang/sciencecity': ('Kota Sains', 'Sebagai satu-satunya kota di Tiongkok yang bergelar Kota Sains dan Teknologi, Mianyang membangun masa depan melalui berbagai laboratorium dan inovasi.'),
  'mianyang/qiang': ('Menara Batu Qiang', 'Di desa-desa pegunungan Beichuan, menara pengawas batu milik suku Qiang telah berdiri kokoh selama berabad-abad.'),
  'mianyang/mifen': ('Mi Beras Mianyang', 'Mi beras halus yang disajikan dalam kaldu ayam dan jeroan panas menjadi menu sarapan khas yang membangunkan kota ini setiap pagi.'),
  'nanchong/langzhong': ('Kota Kuno Langzhong', 'Kota kuno dengan tata letak feng shui yang paling terjaga ini terletak tenang di dalam pelukan kelokan sungai.'),
  'nanchong/silk': ('Ibu Kota Sutra', 'Dengan tradisi menenun selama dua ribu tahun, Nanchong dikenal sebagai ibu kota sutra di wilayah barat Tiongkok.'),
  'nanchong/zhangfei': ('Daging Sapi Zhang Fei', 'Daging sapi olahan berbumbu dari kota pahlawan Tiga Kerajaan, Zhang Fei, dinamai sesuai dengan nama tokoh tersebut.'),
  'nanchong/zhude': ('Kampung Halaman Zhu De', 'Rumah sederhana milik Marsekal Zhu De di Yilong menjadi tempat ziarah sejarah modern yang penting.'),
  'yibin/wuliangye': ('Arak Wuliangye', 'Disuling dari lima jenis biji-bijian, Wuliangye merupakan salah satu merek baijiu paling berharga di Tiongkok.'),
  'yibin/firstcity': ('Kota Pertama di Sungai Yangtze', 'Yibin dijuluki sebagai kota pertama di Sungai Yangtze karena merupakan titik pertemuan sungai Min dan Jinsha yang membentuk aliran sungai tersebut.'),
  'yibin/bamboosea': ('Lautan Bambu Shunan', 'Hamparan hutan bambu yang menutupi seratus dua puluh bukit ini tampak seperti lautan hijau yang bergoyang tertiup angin.'),
  'yibin/ranmian': ('Mi Bakar (Ranmian)', 'Dibuat dengan tekstur yang sangat kering hingga minyaknya bisa tersulut api, ranmian menjadi hidangan sarapan paling populer di Yibin.'),
  'luzhou/laojiao': ('Tempat Penyulingan Laojiao', 'Lubang fermentasi lumpur yang telah digunakan sejak tahun 1573 menjadi kunci utama aroma khas baijiu.'),
  'luzhou/port': ('Pelabuhan Yangtze', 'Kota pelabuhan di pertemuan dua sungai ini merupakan gerbang air Sichuan menuju laut.'),
  'luzhou/longan': ('Kebun Kelengkeng', 'Tumbuh di lereng sungai yang hangat, kelengkeng adalah buah manis madu yang dijuluki sebagai mata naga.'),
  'luzhou/umbrella': ('Payung Kertas Minyak', 'Payung kertas minyak buatan tangan dari pengrajin Fenshui merupakan kerajinan anggun yang telah berusia empat ratus tahun.'),
  'leshan/giantbuddha': ('Patung Buddha Raksasa Leshan', 'Dipahat pada tebing, patung Buddha duduk setinggi 71 meter ini telah mengawasi pertemuan sungai selama dua belas abad.'),
  'leshan/emei': ('Gunung Emei', 'Puncak Emas Emei, salah satu dari empat gunung suci agama Buddha, bersinar megah di atas lautan awan.'),
  'leshan/monkeys': ('Monyet Emei', 'Monyet-monyet nakal di jalur pendakian gunung ini terkenal karena sering menggeledah tas para peziarah dengan berani.'),
  'leshan/qiaojiao': ('Sup Daging Sapi Qiaojiao', 'Sup daging sapi yang direbus dengan rempah-rempah, qiaojiao adalah hidangan klasik berusia seabad yang populer di kedai jalanan Leshan.'),
  'zigong/saltwell': ('Sumur Garam Sedalam Satu Kilometer', 'Sumur Shenhai, sumur pertama di dunia yang menembus kedalaman seribu meter, merupakan pencapaian luar biasa dari kota garam berusia dua ribu tahun ini.'),
  'zigong/lantern': ('Festival Lampion Zigong', 'Taman yang dipenuhi lampion raksasa bercahaya mengubah kota ini menjadi negeri dongeng setiap tahun baru.'),
  'zigong/dinosaur': ('Museum Dinosaurus', 'Ribuan fosil yang ditemukan dari lapisan tanah zaman Jura menjadikan Zigong sebagai ibu kota dinosaurus di Tiongkok.'),
  'zigong/rabbit': ('Daging Kelinci Dingin', 'Hidangan kelinci pedas yang disajikan dingin, lengtu, berasal dari kota ini dan menjadi hidangan pembuka paling berani di Sichuan.'),
  'panzhihua/steel': ('Ibu Kota Vanadium-Titanium', 'Kota baja raksasa yang dibangun di pegunungan ini mengolah cadangan vanadium-titanium terkaya di dunia.'),
  'panzhihua/fruitvalley': ('Lembah Buah Cerah', 'Mangga dan delima dari lembah yang kering dan panas ini dapat matang di bawah sinar matahari bahkan saat musim dingin.'),
  'panzhihua/sunshine': ('Kota Matahari Musim Dingin', 'Dengan 2.700 jam sinar matahari per tahun, Panzhihua menjadi destinasi kesehatan untuk menikmati musim dingin yang sejuk.'),
  'panzhihua/jinsha': ('Sungai Jinsha', 'Sungai Jinsha yang berpasir emas mengalir deras melintasi kota, membentuk lembah-lembah yang dalam.'),
  'dazhou/gas': ('Ibu Kota Gas Alam', 'Ladang gas Puguang yang raksasa menjadikan Dazhou sebagai basis energi gas alam di Tiongkok.'),
  'dazhou/ba': ('Warisan Kerajaan Ba', 'Tanah para pejuang kuno Ba dengan pedang daun dedalu ini terus bercerita melalui situs reruntuhan Luojiaba.'),
  'dazhou/dengying': ('Daging Sapi Dengying', 'Daging sapi pedas yang diiris sangat tipis hingga tembus cahaya ini dinamai berdasarkan seni pertunjukan wayang bayang.'),
  'dazhou/hanque': ('Gerbang Batu Dinasti Han', 'Menara gerbang batu \'que\' berusia dua ribu tahun di Quxian merupakan bukti keanggunan arsitektur Dinasti Han yang masih bertahan.'),
  'guangyuan/jianmen': ('Celah Jianmen', 'Celah gunung pedang yang konon \'satu orang mampu menahan sepuluh ribu musuh\' ini merupakan gerbang utama jalur Shu.'),
  'guangyuan/wuzetian': ('Tempat Kelahiran Wu Zetian', 'Satu-satunya kaisar wanita Tiongkok, Wu Zetian, lahir di sini; Kuil Huangze telah menghormatinya selama satu milenium.'),
  'guangyuan/plankroad': ('Jalan Papan Kuno', 'Jalan papan yang dipaku pada tebing curam menjadi monumen keberanian di jalur Shu yang dikenal \'lebih sulit daripada mendaki ke surga\'.'),
  'guangyuan/cypress': ('Koridor Pohon Sipres Cuiyun', 'Puluhan ribu pohon sipres kuno dari era Tiga Kerajaan mengubah jalan tua tersebut menjadi terowongan hijau yang asri.'),
  'yaan/panda': ('Tempat Kelahiran Panda', 'Panda raksasa pertama kali dideskripsikan secara ilmiah di Baoxing pada tahun 1869; pusat konservasi Bifengxia terus melestarikan warisan tersebut.'),
  'yaan/rain': ('Kota Hujan', 'Hujan Ya yang membasahi atap-atap rumah hampir setiap malam membuat kota ini selalu tampak berkilau dalam balutan warna hijau.'),
  'yaan/mengding': ('Teh Gunung Mengding', 'Teh pertama kali dibudidayakan oleh manusia di Gunung Mengding dua ribu tahun lalu, menjadikannya tempat kelahiran budaya teh.'),
  'yaan/yayu': ('Ikan Ya', 'Ikan Ya yang legendaris dari aliran sungai pegunungan adalah kebanggaan kota yang biasanya disajikan dalam panci panas.'),
  'xianyang/qincapital': ('Ibu Kota Kekaisaran Qin', 'Di sinilah ibu kota Dinasti Qin, sang pemersatu Tiongkok, berdiri; jalan menuju kekaisaran bermula dari Xianyang.'),
  'xianyang/qianling': ('Makam Qianling', 'Makam di atas gunung yang disemayamkan untuk Wu Zetian dan suaminya ini menantang sejarah dengan prasasti kosongnya yang misterius.'),
  'xianyang/zhengguo': ('Kanal Zhengguo', 'Kanal irigasi berusia dua ribu tahun ini mengubah dataran Guanzhong menjadi lumbung pangan bagi Dinasti Qin.'),
  'xianyang/guokui': ('Roti pipih Guokui', 'Roti pipih guokui yang renyah dan sebesar tutup panci merupakan camilan tradisional khas Shaanxi yang telah ada selama berabad-abad.'),
  'baoji/bronze': ('Ibu Kota Perunggu', 'Ribuan artefak perunggu dari Dinasti Zhou, termasuk bejana He Zun yang memuat tulisan pertama nama \'Tiongkok\', ditemukan di Baoji.'),
  'baoji/famen': ('Kuil Famen', 'Sebagai tempat penyimpanan relik tulang jari Buddha, Kuil Famen menjadi harta karun suci bagi para kaisar Dinasti Tang.'),
  'baoji/taibai': ('Gunung Taibai', 'Gunung Taibai setinggi 3.771 meter merupakan puncak tertinggi pegunungan Qinling yang puncaknya tetap bersalju bahkan di musim panas.'),
  'baoji/saozi': ('Mi Saozi', 'Mi saozi khas Qishan dengan kuah daging asam pedas merupakan cita rasa autentik yang mewarisi tradisi kuliner Dinasti Zhou sejak tiga ribu tahun lalu.'),
};
